import{_ as a,o as e,c as b,j as p,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const P=JSON.parse('{"title":"完美潇洒的女仆","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/1.血统与训练/5.通用类/完美潇洒的女仆/完美潇洒的女仆.md","filePath":"4.资源分区/1.血统与训练/5.通用类/完美潇洒的女仆/完美潇洒的女仆.md"}'),s={name:"4.资源分区/1.血统与训练/5.通用类/完美潇洒的女仆/完美潇洒的女仆.md"};function d(o,r,_,l,i,c){return e(),b("div",null,[...r[0]||(r[0]=[p("h1",{id:"完美潇洒的女仆",tabindex:"-1"},[t("完美潇洒的女仆 "),p("a",{class:"header-anchor",href:"#完美潇洒的女仆","aria-label":'Permalink to "完美潇洒的女仆"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风028")])])],-1),n('<h1 id="完美潇洒的女仆-1" tabindex="-1">完美潇洒的女仆 <a class="header-anchor" href="#完美潇洒的女仆-1" aria-label="Permalink to &quot;完美潇洒的女仆&quot;">​</a></h1><p>完美而潇洒的女仆</p><p>她是住在红魔馆并在里面工作的女仆。是被称之为恶魔栖息之馆的红魔馆中唯一的人类，是女仆们的女仆长。<br> 她是个在普通人类不敢接近的地方工作的不可思议的少女。<br> 没人见过她在进入红魔馆之前是怎样的。而且她对幻想乡里人类的来访极为冷淡，常站在妖怪的阵营之中。所以人们觉得她不是幻想乡的人类，有可能是外面世界或者是别的世界来的人。<br> 她没有和村落里任何人类亲近，身上含有许多谜。<br> 不过，当她去村落买东西时，她会一脸愉快，一点也没有敌视人类的样子</p><p>D+600</p><p>【操纵时间程度的能力-加速】：</p><p>她拥有操纵时间程度的能力。不过她自称，她的时间停止能力，其实为超高速的移动能力</p><p>你可以花费一个花招动作加速了自己的时间，进行一次DP为敏捷属性/2点的检定，随后在一轮内，你在以敏捷为关键属性的攻击上获得检定数*1的高速，以此法获得的高速可以在破除全部防御之后转为等量DP。</p><p>【女仆飞刀】：<br> 咲夜是使用飞刀的高手，至于其精准度，如果让妖精女仆头顶苹果站在十二丈外，据说她投出的小刀可以正中妖精女仆的额头，当然，小刀用尽后会停止时间进行回收，投掷完了也会进行回收。</p><p>你现在能以10分/1把的价格购买女仆飞刀。<br> 当你使用【操作时间程度的能力-加速】时，你能够将在本场景中丢出的女仆飞刀回收至手中。</p><p>女仆飞刀<br> 武器分类：匕首<br> 武器伤害：3L<br> 特性：高速1<br> 轻投掷武器：该武器可以敏捷属性进行投掷攻击</p><p>【完美而潇洒的女仆】：</p><p>她红魔馆中的女仆长，唯一的人类。指挥着妖精女仆们。但实际上有没有这群妖精女仆其实无所谓。事实上，所有的工作都是女仆长一人包办的。因为这家的主人就那样，所以实质上，说她是是女仆好呢，还是看孩子的好呢，总之她掌管着这个家。</p><p>你获得特殊计数器女仆心得，这个计数器在你经历第一，二部影片后数值+1，第三部影片后数值+3，第四部结束时+等同于你敏捷与互动（风度、沉着、操控）传奇属性之和的数值<br> 该计数器每有5点，会令你的全检定获得1点dp加值</p><p>C+1200</p><p>女仆技巧：<br> 因为体术也比较熟练，不管是近战还是远距离战斗都能应对。无论怎样的状况都不慌不忙地应对吧。</p><p>现在，你的攻击将获得C级措手不及效果。</p><p>操纵时间程度的能力-加速：<br> 随着血统的开发，你对你那操控时间的能力越发熟练，在瞬间抓住对方的弱点，更快的扔出自己的飞刀。</p><p>现在你在使用该能力时，每点出目会额外提供1点武器伤害。</p><p>B+2400</p><p>「Private Square」<br> 她的能力是发挥时间操纵的本领的「Private Square」，可以攻击由于时间静止而不能动的敌人，也可以将时间放缓而使敌人的移动变得迟钝。<br> 你额外获得4点仅可使用下属技艺的AP。<br> 你的攻击命中时，对方进行一次反射豁免，对抗你的伤害出目，失败则将减少对方等同于你通过操控时间程度能力-加速检定的成功数的AP，最多减少4AP，这是一个B级时空来源的衰竭效果。</p><p>操纵空间程度的能力：<br> 由于能够操作时间就能够操作空间，咲夜也能操作空间，甚至被帕秋莉·诺蕾姬评价为喜爱摆弄空间。<br> 现在，你的移动获得B级时空来源的传送效果。</p><p>A+4800</p><p>膨胀空间：</p><p>操纵时间能力也同样适用于空间。时间减缓等同于压缩空间，时间加速等同于扩展空间。她充分利用了这种超绝能力，应用于打扫、洗衣、料理等各方面。</p><p>你可以将一个事物内部的范围扩大，包括但不限于你的口袋；房间的大小，最多扩大至1000立方米，被扩大的范围视作你创造的异空间，这是一个B级时空来源的异空间效果。<br> 同时，操纵空间的能力使得你可以轻易触碰到远超攻击范围的对手，你的攻击范围将扩大至你的敏感范围。</p><p>操纵时间程度的能力：</p><p>她拥有操纵时间的能力。对人类来说，这是一种最高级的强大的能力，并不是通过修行就能得到的。操纵时间就是停止时间，只有自己能移动。不过现在的你仅仅只可以暂停住一个人的时间。</p><p>你获得S级时间暂停免疫和A级时空来源免疫。<br> 你额外获得4点仅可用来攻击或者使用下属技艺的AP。<br> 花费一个迅捷动作宣言此次攻击，此时你的攻击命中时，被命中的单位将额外进行一次反射豁免，这次豁免不会降低攻击伤害，而是令目标在豁免失败后陷入一轮A级时空来源的时间停止效果，持续一轮，这一效果无论如何只能对单人生效。</p><p>专属物品：</p><p>改良飞刀套组<br> D+500<br> 购买后，你的女仆飞刀武器伤害提升4L<br> 你从身上取出女仆飞刀所需的动作下降一级。<br> 你可以一个花招动作将至多十把女仆飞刀夹至手中，这会令你下一次进行的投掷攻击获得【连射】特性。</p><p>女仆装<br> 500<br> 普普通通的女仆装，穿戴后可以使得自己变得更加优雅<br> 盔甲类型：轻甲<br> 盔甲防御：2/2</p><p>穿戴该女仆装时，可在进入战斗时第一回合花费自由动作提起裙摆，展示自己的优雅，在影片结束时，女仆心得计数器+1，这个效果一影片只可触发1次。</p><p>改造-红魔馆女仆装<br> D+500<br> 红魔馆内随处可见的女仆装，相较于普通女仆装，拥有更好的防御性能和防污渍性能</p><p>盔甲防御额外提升3点</p><p>现在，你在影片内进行各种符合优雅女仆的行为，包括但不限于打扫卫生，卖菜，照顾小孩，用飞刀战斗时，在影片结束时，你的优雅女仆计数器将+1，这个效果一影片最多触发2次。</p><p>改造-红魔馆女仆长女仆装<br> C+1000<br> 红魔馆女仆长专用女仆装，性能和耐久度相较于普通女仆装有了更加优秀的提升</p><p>盔甲防御额外提升8点</p><p>【防弹】【防能量】【适应】<br> 穿着者免疫B级别措手不及</p><p>改造-吸血鬼猎人女仆装<br> B+2000<br> 吸血鬼猎人专用的女仆装，鲜红的命运无时不刻关照着穿戴者，但至于为什么吸血鬼猎人会穿女仆装……不要问</p><p>该升级将不再提高盔甲防御，转而变为5点全伤害吸收</p><p>【防弹】【防能量】</p><p>你可以随时消耗1点计数器点数，令自己下一次的任何行为获得3dp的加值</p><p>你获得飞行能力，机动性为完美</p><p>当穿戴该女仆装，且你的女仆心得计数器超过25点时，你获得【威仪】特性</p><p>当穿戴该女仆装，且你的女仆心得计数器超过30点时，你获得B级免疫胁迫、支配、思维控制效果</p><p>当穿戴该女仆装，且你的女仆心得计数器超过35点时，你获得B级命运来源免疫效果</p><p>专属技艺：</p><p>幻世「The World」</p><p>前提条件：完美潇洒的女仆A级<br> 价格：S+8000<br> 动作：迅捷动作<br> 范围：敏捷*50m<br> 效果：使用后，下一轮开始时，人物率先进行一个特殊的额外回合，但不会因此获得ap点数，人物可以将自身在这一轮内至多传奇敏捷*4点可使用的ap点数分配给这一额外回合使用。<br> 范围内所有受影响单位会处于S级时空来源的时间停止状态。若其免疫了这一效果，其也能够如同你一般获得额外回合并分配自身的ap。在判定执行此特殊回合的先后顺序时，以先攻顺位为准。<br> 当处于该技艺所创造的额外回合时，你的敏捷检定将获得【传奇】特性<br> （其余技艺待更新）</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',51)])])}const f=a(s,[["render",d]]);export{P as __pageData,f as default};
